"""Activity: Union Dissector

Complete a C++ program that uses a union to inspect raw bit patterns. Learn why union type-punning is defined in C but undefined behavior in C++, and what the safe C++ alternatives are.
"""
import os, shutil, subprocess, sys, tempfile, zipfile
import hashlib as _hl, hmac as _hm

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "dcc7fc663784f1e6d16819f06a535e0683baf54657c9718f11664551ac46ef4efe2a7264f3195ea6f6014c3ed2c5626438d967a90bbe0fd04f"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)

def _build(repo_dir):
    r = subprocess.run(["make"], capture_output=True, text=True, cwd=repo_dir)
    return r.returncode == 0, r.stderr

def _run_lab(repo_dir):
    try:
        r = subprocess.run(
            ["./union_lab"], capture_output=True, text=True, timeout=10, cwd=repo_dir,
        )
        return r.stdout.strip(), None
    except subprocess.TimeoutExpired:
        return None, "timeout"
    except Exception as e:
        return None, str(e)

def main():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")

    work_dir = tempfile.mkdtemp(prefix="union-dissector-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    repo_dir = os.path.join(work_dir, entries[0])

    banner_text = (
        "\n"
        "      ============================================================\n"
        "       Activity: Union Dissector\n"
        "      ============================================================\n"
        "\n"
        "       A C++ program with four TODOs.  Your job: fill them in, build, and run.\n       \n       NOTE: In C, union type-punning (reading a member you did not write) is\n       defined behavior (C11 6.5.2.3).  In C++, it is technically undefined\n       behavior.  GCC and Clang support it as an extension.  The safe C++\n       alternatives are std::memcpy (C++11) and std::bit_cast<T> (C++20).\n       The README explains when to use each approach.\n       \n       Step 1 -- read the starter file to understand the union definition\n         cat union_lab.cpp\n       \n       Step 2 -- fill in TODO 1 (store 0x3F800000, read back as float)\n         Open union_lab.cpp in your editor and complete the first TODO block.\n         Expected output line: as_float: 1\n       \n       Step 3 -- fill in TODO 2 (print all 4 bytes as hex)\n         Loop over bv.bytes[0..3] and print each as a 2-digit hex number.\n         Expected output line: bytes: 00 00 80 3f\n       \n       Step 4 -- fill in TODO 3 (store -0.0f, read back as uint hex)\n         Expected output line: neg_zero_bits: 80000000\n       \n       Step 5 -- fill in TODO 4 (print sizeof the union)\n         Expected output line: sizeof(ByteView): 4\n       \n       Step 6 -- build and run\n         make\n         ./union_lab\n       \n       When the output matches all four expected lines, type 'exit'.\n"
        "      ============================================================\n"
        "\n"
    )
    rcfile = __import__('tempfile').NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        'PS1=\'\\u@union-dissector:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "echo " + repr(banner_text) + "\n"
    )
    rcfile.close()

    shell = os.environ.get("SHELL", "/bin/bash")

    try:
        while True:
            subprocess.run([shell, "--rcfile", rcfile.name])

            print()
            _banner("Activity: Union Dissector -- Checking Your Work")
            print()

            build_ok, build_err = _build(repo_dir)
            if not build_ok:
                print("  make failed.  Fix the compilation errors first.")
                for line in build_err.strip().splitlines()[:10]:
                    print(f"    {line}")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            output, err = _run_lab(repo_dir)
            if output is None:
                print(f"  union_lab did not run: {err}")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            passphrase = _decrypt(output)
            if passphrase is not None:
                _show_passphrase(passphrase)
                break

            print("  union_lab ran but the output did not match the expected lines.")
            print("  Check each TODO: the exact format of each printf line matters.")
            print()
            print("  Your output was:")
            for line in output.splitlines():
                print(f"    {line}")
            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                break
            if again == "y":
                print()
                continue
            break

    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass
        shutil.rmtree(work_dir, ignore_errors=True)


if __name__ == "__main__":
    main()
